class Solution {
public:
    int peopleAwareOfSecret(int n, int delay, int forget) {
        long long MOD = 1e9 + 7;
        vector<long long> dp(forget + 1, 0);
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = max(0, i - forget); j <= i - delay; j++) {
                dp[i % (forget + 1)] = (dp[i % (forget + 1)] + dp[j]) % MOD;
            }
        }
        return dp[n % (forget + 1)];
    }
};
```
